import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { FormControl } from '@material-ui/core';
import { classActions } from '../../actions';
import { classStrings } from '../../config';
import { MyPopupMenu } from '../../../../includes';

const style = theme => ({
    root: {
    }
})
class _ClassTimeTableHeaderComponent extends Component {
    constructor(props) {
        super(props);
        this.initialiseComponent();
    }
    initialiseComponent(){
        const {
            [classStrings.selectedLevel] : selectedLevel,
            dispatch 
        } = this.props;
        classActions.getTerms(/* selectedLevel._id */1)(dispatch);
    }
    setSelectedTerm = term => {
        const {
            dispatch,
            [classStrings.selectedLevel] : selectedLevel,
            [classStrings.selectedClass] : selectedClass,
        } = this.props;
        classActions.setSelectedTerm(term)(dispatch);
        classActions.getSubjectsAndAssessments(/* selectedLevel._id */1, term._id)(dispatch);
        classActions.getClassStudentsAndAssessments(/*selectedLevel._id*/1, term._id, /*class._id*/1)(dispatch);
        classActions.getClassTimeTable(
            1, 1, 1
        )(dispatch);
    }
    render() {
        const {
            classes,
            [classStrings.selectedTerm] : selectedTerm,
            [classStrings.terms] : terms,
        } = this.props;
        return (
            <div className={classes.root}>
                <FormControl>
                    <MyPopupMenu
                        buttonValue={(selectedTerm && selectedTerm.name) || "Terms"}
                        buttonName="terms"
                        optionNameProp="name"
                        optionValueProp="_id"
                        options={terms}
                        optionClickCallback={this.setSelectedTerm.bind(this)}/>
                </FormControl>
            </div>
        );
    }
}


_ClassTimeTableHeaderComponent.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({classReducer}) => ({
    [classStrings.selectedTerm] : classReducer[classStrings.selectedTerm],
    [classStrings.terms] : classReducer[classStrings.terms],
    [classStrings.selectedLevel] : classReducer[classStrings.selectedLevel],
    [classStrings.selectedClass] : classReducer[classStrings.selectedClass],
})


export const ClassTimeTableHeaderComponent = connect(mapStateToProps)(withStyles(style)(_ClassTimeTableHeaderComponent));