import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { headerActions, breadCrumbActions, mainStageHeaderAction, mainStageHeaderStrings, HighlightedInfo, MyTable, EditableCellMapFormat, headerStrings } from '../../../includes';
import { ClassHeader } from './ClassHeader';
import { classStrings } from '../config';
import { Typography } from '@material-ui/core';
import { classActions } from '../actions';
import { routeNamesSchool } from '../../routeNames';

const style = theme => ({
    root: {
        marginTop : 50
    }
})
class _ClassList extends Component {
    constructor(props) {
        super(props);
        this.state = {
            levelClasses : null,
            levelClassesUnusuable : null
        }
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "CLASSES (LIST)"
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : routeNamesSchool.dashboard},
            {name : "Classes", path : routeNamesSchool.class}
        ])(dispatch);
        mainStageHeaderAction({
            [mainStageHeaderStrings.components] : [
                ClassHeader
            ]
        })(dispatch);
        this.initializeComponent();
    }
    initializeComponent(){

    }
    static getDerivedStateFromProps(nextProps, prevState) {
        const {
            [classStrings.classes] : propClasses
        } = nextProps
        const {levelClassesUnusuable} = prevState;
        if(!levelClassesUnusuable && propClasses){
            prevState.levelClasses = propClasses;
            prevState.levelClassesUnusuable = propClasses;
        }else if(JSON.stringify(levelClassesUnusuable) 
            !== JSON.stringify(propClasses)){
                prevState.levelClassesUnusuable = propClasses ? [...propClasses]: [];
                prevState.levelClasses = propClasses ? [...propClasses]: [];
        }
        return prevState;
    }
    
    setListEditMode(){
        const {dispatch, [classStrings.listEditMode] : editMode} = this.props;
        classActions.setListEditMode(!editMode)(dispatch);
    }
    cellMapFormat = superProps=>props=>{
        return <EditableCellMapFormat {...props} {...superProps}/>
    }
    viewBtnHandler = row => () => {
        this.props.superSetState({page: "classView"});
        classActions.setSelectedClass(row)(this.props.dispatch);
    }
    deleteBtnHandler = row => () =>{

    }
    editBtnHandler = row => () =>{
        const { levelClasses } = this.state;
        if(levelClasses){
            const {index} = levelClasses.getFirstObjectByPropValue("_id", row._id);
            row.editing = true;
            levelClasses[index] = row;
            this.setState({levelClasses});
        }
    }
    addButtonHandler = length => () =>{

    }
    editFinishBtnHandler = row => () =>{
        
    }
    cancelEditBtnHandler = row => () =>{
        const { levelClasses } = this.state;
        if(levelClasses){
            const {index} = levelClasses.getFirstObjectByPropValue("_id", row._id);
            delete row.editing;
            levelClasses[index] = row;
            this.setState({levelClasses});
        }
    }
    render() {
        let {
            classes,
            [classStrings.selectedLevel] : selectedLevel,
            [classStrings.listEditMode] : listEditMode
        } = this.props;
        let { levelClasses } = this.state;
        if(levelClasses){
            if(listEditMode) levelClasses = [
                ...levelClasses.map(
                    item=>({
                        ...item, 
                        editable: true, 
                        delible : true,
                    })
                ), 
                {new : true}
            ];else levelClasses = [
                ...levelClasses.map(
                    item=>({
                        ...item, 
                        view : true
                    })
                )
            ]
        }else levelClasses = [{new : true}];
        return (
            <div className={classes.root}>
                {!selectedLevel ? <HighlightedInfo>
                    Select a level above to view the list of class
                </HighlightedInfo> :
                (levelClasses ? <MyTable
                    title={selectedLevel.name + " classes"}
                    header={["ID", "Name", "Short Name", "Actions"]}
                    dataMap={["_id", "name", "short", "action"]}
                    data={levelClasses}
                    CellMap={this.cellMapFormat({
                        skipEdit: ["_id"],
                        deleteBtnHandler:this.deleteBtnHandler.bind(this),
                        editBtnHandler:this.editBtnHandler.bind(this),
                        addButtonHandler:this.addButtonHandler.bind(this),
                        editFinishBtnHandler:this.editFinishBtnHandler.bind(this),
                        cancelEditBtnHandler:this.cancelEditBtnHandler.bind(this),
                        viewBtnHandler:this.viewBtnHandler.bind(this)
                    })}
                    /> : 
                    <div>
                        <Typography>There is no class enlisted in this level</Typography>
                </div>)}
            </div>
        );
    }
}


_ClassList.propTypes = {
    classes : PropTypes.object.isRequired
};

const mapStateToProps = ({classReducer}) => ({
    [classStrings.selectedLevel] : classReducer[classStrings.selectedLevel],
    [classStrings.classes] : classReducer[classStrings.classes],
    [classStrings.listEditMode] : classReducer[classStrings.listEditMode],
})


export const ClassList = connect(mapStateToProps)(withStyles(style)(_ClassList));