import React, {Component} from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core';
import {connect} from 'react-redux';
import { classActions } from '../../actions';
import { classStrings } from '../../config';
import { mainStageHeaderAction, mainStageHeaderStrings, MyTable, HighlightedInfo } from '../../../../includes';
import { StageHeaderComponent } from './StageHeaderComponent';
import { scorePositionLiteral } from '../../../../../utils';

const styles = theme => ({
    marginTop : 30
})
class _ClassStudents extends Component {
    constructor(props){
        super(props);
        const { dispatch } = props;
        mainStageHeaderAction({
            [mainStageHeaderStrings.components] : [
                StageHeaderComponent
            ],
            [mainStageHeaderStrings.buttons] : [
                {value : "Back", onClick : this.props.goBack}
            ]
        })(dispatch)
    }
    initializeComponent(){
        const {
            [classStrings.selectedLevel] : selectedLevel,
            [classStrings.selectedTerm] : selectedTerm,
            dispatch
        } = this.props;

        classActions.getSubjectsAndAssessments(
            selectedLevel._id, selectedTerm._id
        )(dispatch);
    }
    subHeaderMap = subHeader => {
        if(!subHeader) return null;
        let newSubHeader = subHeader;
        const {
            [classStrings.subjectsAndAssessments] : subjectsAndAssessments,
            [classStrings.selectedTerm] : selectedTerm
        } = this.props;
        const {assessmentNames} = subjectsAndAssessments[selectedTerm._id];
        if(assessmentNames){
            const {item} = assessmentNames.getFirstObjectByPropValue("_id", subHeader);
            if(item) newSubHeader = item.name;
        }
        return newSubHeader
    }
    transformData=students=>{
        let data = [];
        const a = {
            _id : 1, 
            studentId : 1,
            levelId : 1,
            classId : 1,
            terms : [
                {
                    _id : 1, 
                    termId : 1,
                    subjects : [
                        {
                            _id : 1, 
                            sessionSubjectId : 1,
                            assessments : [
                                {_id : 1, assessmentIds : 1, score : 20},
                                {_id : 2, assessmentIds : 2, score : 20},
                                {_id : 3, assessmentIds : 3, score : 60},
                            ],
                        }
                    ],
                }
            ]
        }
        if(students) for (let i = 0; i < students.length; i++) {
            const student = students[i];
            const {student : studentInfo, terms} = student;
            let dataInfo = {Students : studentInfo.fullName};
            if(terms) for (let j = 0; j < terms.length; j++) {
                const term = terms[j];
                const {subjects} = term;
                let total=0;
                if(subjects){
                    for (let k = 0; k < subjects.length; k++) {
                        const subject = subjects[k];
                        const {sessionSubjectId, assessments} = subject;
                        if(assessments){
                            for (let l = 0; l < assessments.length; l++) {
                                const assess = assessments[l];
                                dataInfo[sessionSubjectId+"_"+assess._id] = assess.score;
                                total += assess.score;
                            }
                        }
                    }
                    dataInfo.Total = total 
                }
            }
            data.push(dataInfo);
        }
        return data.sort(
            (a, b) => b.Total - a.Total
        ).map((item, index)=>({
            ...item, 
            Position : scorePositionLiteral(index + 1)
        }));
    }
    render(){
        const {
            classes,
            [classStrings.subjectsAndAssessments] : subjectsAndAssessments,
            [classStrings.selectedTerm] : selectedTerm,
            [classStrings.classStudents] : classStudents
        } = this.props;
        return (
            <div className={classes.root}>
                {subjectsAndAssessments ? <MyTable
                    getContext={context => this.tableContext = context}
                    multiRowHeader={[
                        {subjectName : "Students"}, 
                        ...subjectsAndAssessments[selectedTerm._id].subjects,
                        {subjectName : "Total"},
                        {subjectName : "Position"},
                    ]}
                    headerName="subjectName"
                    subheaderIndicator="assessmentIds"
                    subHeaderMap={this.subHeaderMap.bind(this)}
                    data={this.transformData(classStudents)}
                /> : 
                <HighlightedInfo>
                    Please select a term to view the class score sheet
                </HighlightedInfo>}
            </div>
        )
    }
}
_ClassStudents.propTypes = {
    goBack : PropTypes.func,
}
const mapStateToProps = ({studentReducer, classReducer}) =>({
    [classStrings.subjectsAndAssessments] : classReducer[classStrings.subjectsAndAssessments],
    [classStrings.selectedTerm] : classReducer[classStrings.selectedTerm],
    [classStrings.classStudents] : classReducer[classStrings.classStudents],
});
export const ClassStudents = connect(mapStateToProps)(withStyles(styles)(_ClassStudents));