import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { MyCustomTabs } from '../../../includes';
import { ClassStudents } from './ClassStudents';
import { ClassTimeTable } from './ClassTimeTable';

const styles = theme => ({
    root: {
    }
})
class _ClassView extends Component {
    constructor(props) {
        super(props);
        this.state = {
            tabValue : null
        }
        const{dispatch} = props;
        
    }
    
    render() {
        const {classes} = this.props;
        const {tabValue} = this.state;
        return (
            <div className={classes.root}>
                <MyCustomTabs
                    position="sticky"
                    tabs={{
                        timeTable : "Time Table",
                        students : "Students",
                        reports : "Reports",
                        leadership :"Leadership",
                    }}
                    getInitialTabValue={tabValue => this.setState({tabValue})}
                />
                <div style={{marginTop : 40}}>
                    {tabValue === "students" && <ClassStudents goBack={this.props.goBack}/>}
                    {tabValue === "timeTable" && <ClassTimeTable goBack={this.props.goBack}/>}

                </div>
            </div>
        );
    }
}


_ClassView.propTypes = {
    classes : PropTypes.object.isRequired,
    goBack : PropTypes.func,
};
const mapStateToProps = state => ({
    state
})


export const ClassView = connect(mapStateToProps)(withStyles(styles)(_ClassView));