import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { headerActions, breadCrumbActions, headerStrings } from '../../includes';
import { routeName, customSuperSetState } from '../../../utils';
import { ClassView } from './ClassView';
import { ClassList } from './ClassList/ClassList';
import { sessionStrings, sessionActions } from '../Sessions';


const style = theme => ({
    root: {
    }
})
class _Classes extends Component {    
    constructor(props) {
        super(props);
        this.state = {
            page : "home",
        }
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "CLASSES"
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : routeName.dashboard},
            {name : "Classes", path : routeName.class},
        ])(dispatch);
        this.mySetState = customSuperSetState(this);
        this.initializeComponent();
    }
    initializeComponent(){
        const {
            dispatch, 
            [sessionStrings.levels] : levels
        } = this.props;
        if(!levels) sessionActions.getCurrentSessionLevel()(dispatch);
    }
    render() {
        const {classes} = this.props;
        const {page} = this.state;
        return (
            <div className={classes.root}>
                {page === "home" && <ClassList superSetState={this.mySetState}/>}
                {page === "classView" && <ClassView goBack={()=>this.setState({page : "home"})}/>}
            </div>
        )
    }
}


_Classes.propTypes = {
    classes : PropTypes.object.isRequired
};

const mapStateToProps = ({classReducer, sessionReducer}) => ({
    [sessionStrings.levels] : sessionReducer[sessionStrings.levels],
})


export const Classes = connect(mapStateToProps)(withStyles(style)(_Classes));
export {Classes as default};