import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { classStrings } from '../config';
import { sessionStrings } from '../../Sessions';
import { FormGroup, Button, FormControl} from '@material-ui/core';
import { classActions } from '../actions';
import { colors } from '../../../../utils';
import { MyPopupMenu } from '../../../includes';


const style = theme => ({
    root: {
        padding : 10,
        display : "flex",
        flexDirection : "row"
    },
    fControl : {
        margin : 5,
        backgroundColor : colors.secondary,
        borderRadius : 5
    },
    fControlCB : {
        margin : 5,
        justifyContent : "flex-end"
    }
})
class _ClassHeader extends Component {
    constructor(props) {
        super(props);
        const {dispatch} = props;
    }
    setSelectedLevel = level => {
        const {dispatch} = this.props;
        classActions.setSelectedLevel(level)(dispatch);
        classActions.getLevelClasses(level._id)(dispatch);
    }
    setListEditMode(){
        const {dispatch, [classStrings.listEditMode] : editMode} = this.props;
        classActions.setListEditMode(!Boolean(editMode))(dispatch);
    }
    cancelEdit = () => {
        const {dispatch} = this.props;
        classActions.setListEditMode(false)(dispatch);
    }
    render() {
        const {classes, 
            [sessionStrings.levels] : levels,
            [classStrings.selectedLevel] : selectedLevel,
            [classStrings.listEditMode] : editMode
        } = this.props;
        return (
            <div className={classes.root}>
                <MyPopupMenu
                    buttonName="level"
                    buttonValue={(selectedLevel && selectedLevel.name) || "Levels"}
                    optionNameProp="name"
                    optionValueProp="_id"
                    options={levels}
                    optionClickCallback={level=>this.setSelectedLevel(level)}
                    />
                <div style={{display : "flex", flexGrow: 1}}/>
                <FormControl style={{margin : 10}}>
                    <Button 
                        style={{color : colors.white}}
                        onClick={this.setListEditMode.bind(this)}>
                            {editMode ? "Save" : "Edit"}
                    </Button>
                </FormControl>
                {editMode && <FormControl style={{margin : 10}}>
                    <Button 
                        color="secondary"
                        onClick={this.cancelEdit.bind(this)}>
                            Cancel
                    </Button>
                </FormControl>}
            </div>
        );
    }
}


_ClassHeader.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({classReducer, sessionReducer}) => ({
    [sessionStrings.levels] : sessionReducer[sessionStrings.levels],
    [classStrings.selectedLevel] : classReducer[classStrings.selectedLevel],
    [classStrings.listEditMode] : classReducer[classStrings.listEditMode]
});
export const ClassHeader = connect(mapStateToProps)(withStyles(style)(_ClassHeader));